import React from "react";


import { useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!name.trim()) return;

    if (editingId) {
      // Update
      setLinks(
        links.map((link) =>
          link.id === editingId ? { ...link, name } : link
        )
      );
      setEditingId(null);
    } else {
      // Create
      const newLink = {
        id: Date.now(),
        name,
      };
      setLinks([...links, newLink]);
    }

    setName("");
  };

  const handleEdit = (link) => {
    setName(link.name);
    setEditingId(link.id);
  };

  const handleDelete = (id) => {
    setLinks(links.filter((link) => link.id !== id));
  };

  return (
    <div className="p-6">
      {/* Title */}
      <h1 className="text-2xl font-semibold mb-6">Link Management</h1>

      {/* Form */}
      <form
        onSubmit={handleSubmit}
        className="bg-white p-4 rounded-xl shadow-md mb-6 flex gap-3"
      >
        <input
          type="text"
          placeholder="Enter link name..."
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="flex-1 border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-indigo-500"
        />

        <button
          type="submit"
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
        >
          <Plus size={16} />
          {editingId ? "Update" : "Add"}
        </button>
      </form>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden">
        {links.length === 0 ? (
          <div className="p-6 text-gray-500 text-center">
            No links created yet.
          </div>
        ) : (
          <table className="w-full text-left">
            <thead className="bg-gray-100 text-sm text-gray-600">
              <tr>
                <th className="px-4 py-3">Name</th>
                <th className="px-4 py-3 text-right">Actions</th>
              </tr>
            </thead>

            <tbody>
              {links.map((link) => (
                <tr key={link.id} className="border-t">
                  <td className="px-4 py-3">{link.name}</td>

                  <td className="px-4 py-3 flex justify-end gap-3">
                    <button
                      onClick={() => handleEdit(link)}
                      className="text-indigo-600 hover:text-indigo-800"
                    >
                      <Pencil size={18} />
                    </button>

                    <button
                      onClick={() => handleDelete(link.id)}
                      className="text-red-600 hover:text-red-800"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default LinkHome;
